mapper.select:
WITH scoped AS ( SELECT op.opid, op.uid, op.tenant_id, op.building_id, op.room_id, op.build_area, op.is_voting_delegate, op.account_status, CASE WHEN op.account_status = 1 THEN 1 ELSE 4 END AS eligibility_flag FROM c_owner_property op WHERE op.tenant_id = #{tenantId} AND op.account_status = 1
AND op.building_id = #{scopeReferenceId}
), ranked_room AS ( SELECT s.*, ROW_NUMBER() OVER ( PARTITION BY s.tenant_id, s.room_id ORDER BY s.is_voting_delegate DESC, s.opid ASC ) AS room_rn FROM scoped s ), co_owners AS ( SELECT tenant_id, room_id, STRING_AGG(uid::TEXT, ',' ORDER BY uid) AS co_owner_uids FROM scoped GROUP BY tenant_id, room_id ) SELECT rr.room_id, rr.building_id, rr.build_area AS certified_area, rr.uid AS primary_owner_uid, co.co_owner_uids, rr.eligibility_flag FROM ranked_room rr INNER JOIN co_owners co ON co.tenant_id = rr.tenant_id AND co.room_id = rr.room_id WHERE rr.room_rn = 1 ORDER BY rr.building_id, rr.room_id
